import openai

client = openai.OpenAI()

def detect_injection_in_run(thread_id, run_id):
    run = client.beta.threads.runs.retrieve(thread_id=thread_id, run_id=run_id)
    messages = client.beta.threads.messages.list(thread_id=thread_id)

    suspicious_phrases = ['ignore previous', 'forget your', 'override instructions', 'you are now']

    for msg in messages.data:
        content = msg.content[0].text.value.lower()
        if any(phrase in content for phrase in suspicious_phrases):
            if run.status == 'completed' and 'tool_calls' in run.required_action:
                return {'injected': True, 'evidence': content[:100]}
    return {'injected': False}

from openai import OpenAI
import json

client = OpenAI()

def validate_tool_calls(run):
    if hasattr(run, 'required_action') and run.required_action.type == 'submit_tool_outputs':
        for tool_call in run.required_action.submit_tool_outputs.tool_calls:
            args = json.loads(tool_call.function.arguments)
            # Check for schema violations or suspicious content
            if 'rm -rf' in str(args) or 'delete' in str(args):
                return {'violation': True, 'args': args}
    return {'violation': False}

