import vex

@vex.hook('openai.assistants.run.completed')
def verify_assistant_run(run_data):
    thread_id = run_data['thread_id']
    run_id = run_data['id']

    # Vex auto-detects injections
    if vex.detect.prompt_injection(run_data):
        vex.quarantine.thread(thread_id)
        vex.log.severity('CRITICAL', 'Prompt injection detected', run_data)
        return vex.block('Injection detected - thread quarantined')

    # Validate tool calls
    tool_calls = run_data.get('required_action', {}).get('submit_tool_outputs', {}).get('tool_calls', [])
    for call in tool_calls:
        if vex.validate.schema_violation(call['function']['arguments']):
            return vex.block('Schema violation in tool call')

    return vex.approve()

# Install: pip install vex-sdk openai
# vexctl webhook --provider openai --event run.completed
